  async function search(word, autoPlayFirst=false, showList=true, heading='') { word = String(word || '').trim(); if (!word) return; setStatus('正在搜索…'); const gd=async source=>{const u=new URL(GD_API);u.searchParams.set('types','search');u.searchParams.set('source',source);u.searchParams.set('name',word);u.searchParams.set('count','20');u.searchParams.set('pages','1');const r=await fetch(u);if(!r.ok)throw Error(`搜索失败：${r.status}`);const data=await r.json(),rows=Array.isArray(data)?data:(data.data||[]);return rows.map((x,i)=>({id:`${source}:${x.id||i}`,mediaId:String(x.id||''),title:x.name||x.title||'',artist:x.artist?.map?.(a=>a.name).join('/')||x.artist||x.singer||'',cover:x.pic||x.picUrl||x.album?.picUrl||'',coverId:String(x.pic_id||''),lyricId:String(x.lyric_id||x.id||''),audio:'',source}));};const settled=await Promise.allSettled(GD_SOURCES.map(gd)),rows=[];settled.forEach(x=>{if(x.status==='fulfilled')rows.push(...x.value);});results=rows.filter((s,i,a)=>s.title&&a.findIndex(x=>x.title===s.title&&x.artist===s.artist)===i);const listBox=DOC.querySelector(`#${ID} .list`);if(showList)render(results,heading,'results',false);else if(listBox){listBox.hidden=true;listBox.innerHTML='';}if(results.length){setStatus(`${results.length} 个全网结果`);if(autoPlayFirst){await play(results[0]);if(showList)ROOT.setTimeout(()=>hydrateResultCovers(results,heading),600);}else if(showList){ROOT.setTimeout(()=>hydrateResultCovers(results,heading),0);}}else{const failed=settled.filter(x=>x.status==='rejected');const msg=failed[0]?.reason?.message||'没有找到歌曲';setStatus(msg);toast('error',msg);}}
