  async function hydrateResultCovers(rows,heading=''){if(!Array.isArray(rows)||rows._coverHydrating||rows._coversHydrated)return;rows._coverHydrating=true;try{for(const song of rows.slice(0,10)){if(results!==rows)break;if(!song.cover)song.cover=await gdCover(song)||await metingCover(song);await coverDelay(120);}rows._coversHydrated=true;}catch(error){console.warn('[音乐播放器] 候选列表封面加载失败',error);}finally{rows._coverHydrating=false;}if(results===rows)render(rows,heading,'results',false);}
  function render(rows, heading='', kind='results', hydrateCovers=true) { const box=DOC.querySelector(`#${ID} .list`),saved=kind==='fav'||kind==='queue',headingActions=saved?`${kind==='fav'?'<button data-heading-action="clear">清空收藏</button><button data-heading-action="queue">收藏入队</button>':'<button data-heading-action="clear">清空队列</button>'}<button data-heading-action="play">一键播放</button>`:'';box.hidden=false;box.innerHTML=`${heading?`<div class="row${saved?' batch-heading':''}"><b>${esc(heading)}</b>${headingActions}</div>`:''}${rows.map((s,i)=>`<article class="row" data-i="${i}"><img loading="lazy" decoding="async" ${s.cover?`src="${esc(s.cover)}"`:''} onerror="this.onerror=null;this.removeAttribute('src');this.style.visibility='visible'"><div><b>${esc(s.title)}</b><span>${esc(s.artist)}</span></div>${saved?`${kind==='fav'?`<button data-q="${i}" title="加入播放队列">＋</button>`:''}${kind==='queue'?`<button data-save="${i}" title="加入收藏">☆</button>`:''}<button data-del="${i}" title="删除">×</button>`:`<button data-f="${i}">☆</button><button data-q="${i}">＋</button>`}</article>`).join('')||'<div class="row">没有歌曲</div>'}`;box.onclick=e=>{const headingAction=e.target.closest('[data-heading-action]')?.dataset.headingAction;if(headingAction){if(headingAction==='clear'){if(kind==='queue'){if(!queue.length){setStatus('播放队列已经是空的');return;}if(!ROOT.confirm?.('确定清空整个播放队列吗？'))return;queue=[];queueIndex=-1;count();render(queue,'播放队列','queue',false);setStatus('已清空播放队列');return;}if(!(settings.favorites||[]).length){setStatus('收藏已经是空的');return;}if(!ROOT.confirm?.('确定清空全部收藏歌曲吗？此操作无法撤销。'))return;settings.favorites=[];save();render(settings.favorites,'收藏歌曲','fav',false);setStatus('已清空全部收藏歌曲');return;}if(headingAction==='queue'){const known=new Set(queue.map(x=>x.id));let added=0;for(const song of settings.favorites||[])if(!known.has(song.id)){queue.push(strip(song));known.add(song.id);added++;}count();setStatus(added?`已将 ${added} 首收藏加入播放队列`:'收藏歌曲已在播放队列中');return;}if(kind==='fav'){queue=(settings.favorites||[]).map(strip);count();}if(!queue.length){setStatus('没有可播放的歌曲');return;}queueIndex=0;play(queue[0]);return;}const row=e.target.closest('[data-i]');if(!row)return;const i=+row.dataset.i,s=rows[i];if(e.target.closest('[data-del]')){if(kind==='fav'){settings.favorites.splice(i,1);save();}else{queue.splice(i,1);if(queueIndex>=queue.length)queueIndex=queue.length-1;count();}render(kind==='fav'?settings.favorites:queue,heading,kind,false);}else if(e.target.closest('[data-save]')){saveFavorite(s);setStatus('已加入收藏');}else if(e.target.closest('[data-f]'))favorite(s);else if(e.target.closest('[data-q]')){queue.push(strip(s));count();if(kind==='fav')setStatus('已加入播放队列');}else{if(kind==='queue')queueIndex=i;play(s);}};if(hydrateCovers){if(kind==='results')ROOT.setTimeout(()=>hydrateResultCovers(rows,heading),0);else if(kind==='fav'||kind==='queue')ROOT.setTimeout(()=>hydrateSavedCovers(rows,heading,kind),0);} }
  const strip = s => ({ id:s.id,mediaId:s.mediaId||s.id,title:s.title,artist:s.artist,cover:s.cover,coverId:s.coverId||'',lyricId:s.lyricId||'',audio:s.audio||'',source:s.source||'netease' });
