  function extractLyrics(data){const groups=[data,data?.data,data?.result,data?.data?.[0],data?.result?.[0]],pick=keys=>{for(const group of groups)for(const key of keys){const text=lyricText(group?.[key]);if(text)return text;}return '';};return {original:pick(['lyric','lrc','yrc']),translation:pick(['tlyric','translation','translatedLyric','transLyric','trans','translate','lyricTranslation'])};}
  function parseLrcGroups(text){const map=new Map();for(const line of String(text||'').split(/\r?\n/)){const times=[...line.matchAll(/\[(\d+):(\d+(?:\.\d+)?)\]/g)].map(m=>Number(m[1])*60+Number(m[2])),words=line.replace(/\[[^\]]+\]/g,'').trim();if(!words||!times.length)continue;for(const time of times){const key=Math.round(time*100)/100,entry=map.get(key)||{time:key,lines:[]};if(!entry.lines.includes(words))entry.lines.push(words);map.set(key,entry);}}return [...map.values()].sort((a,b)=>a.time-b.time);}
  function mergeLyricTimeline(originalText,translationText){const original=parseLrcGroups(originalText),translated=parseLrcGroups(translationText),used=new Set(),timeline=original.map(item=>({time:item.time,lines:[...item.lines]}));for(const row of timeline){let best=-1,diff=1.6;for(let i=0;i<translated.length;i++){if(used.has(i))continue;const d=Math.abs(translated[i].time-row.time);if(d<diff){diff=d;best=i;}}if(best>=0){used.add(best);for(const line of translated[best].lines)if(!row.lines.includes(line))row.lines.push(line);}}if(!timeline.length){for(const item of translated)timeline.push({time:item.time,lines:[...item.lines]});}return timeline.sort((a,b)=>a.time-b.time);}
  function scoreSongHit(item,song){const title=normalizeSongText(getSongTitle(item)),artist=getSongArtist(item),wantedTitle=normalizeSongText(song?.title),wantedArtist=String(song?.artist||'');if(!title||!wantedTitle||title!==wantedTitle||!artistMatches(artist,wantedArtist))return-Infinity;let score=1000;if(normalizeSongText(artist)===normalizeSongText(wantedArtist))score+=300;const itemId=String(item?.id||item?.songmid||''),oldId=String(song?.mediaId||'').replace(/^\w+:/,'');if(itemId&&oldId&&itemId===oldId)score+=20;return score;}
  const scoreLyricHit = scoreSongHit;
  function bestSongHit(rows,song){return(Array.isArray(rows)?rows:[]).map(item=>({item,score:scoreSongHit(item,song)})).filter(x=>Number.isFinite(x.score)).sort((a,b)=>b.score-a.score)[0]?.item||null;}
  async function fetchLyricPayload(source,id){if(!source||!id)return null;const u=new URL(GD_API);u.searchParams.set('types','lyric');u.searchParams.set('source',source);u.searchParams.set('id',id);const r=await fetch(u);if(!r.ok)throw Error(`歌词请求失败：${source}/${r.status}`);const data=await r.json(),extracted=extractLyrics(data);return {source,id,original:extracted.original,translation:extracted.translation,raw:data};}
