  function lastLyricTime(text){let last=0;for(const line of String(text||'').split(/\r?\n/))for(const match of line.matchAll(/\[(\d+):(\d+(?:\.\d+)?)\]/g))last=Math.max(last,Number(match[1])*60+Number(match[2]));return last;}
  function lyricFitsAudio(text){const lyricEnd=lastLyricTime(text),duration=Number(audio?.duration);if(!lyricEnd||!Number.isFinite(duration)||duration<20)return true;return Math.abs(duration-lyricEnd)<=Math.max(18,duration*.12);}
  function lyricTimelinesMatch(a,b){const endA=lastLyricTime(a),endB=lastLyricTime(b);return!!endA&&!!endB&&Math.abs(endA-endB)<=Math.max(8,Math.max(endA,endB)*.06);}
  async function resolveLyrics(song){const primarySource=song.gdSource||song.source||'netease',primaryId=song.gdLyricId||song.lyricId||song.mediaId||String(song.id||'').replace(/^\w+:/,''),key=`${primarySource}:${primaryId}`;if(lyricCache.has(key))return lyricCache.get(key);let original='',translation='',resultSource=primarySource,resultId=primaryId,raw=null;try{const primary=await fetchLyricPayload(primarySource,primaryId);raw=primary?.raw||null;if(primary?.original&&lyricFitsAudio(primary.original))original=primary.original;if(primary?.translation&&(!original||lyricTimelinesMatch(original,primary.translation)))translation=primary.translation;}catch(error){console.warn('[音乐播放器] 当前音源精确歌词失败',error);}if(original&&!translation)try{const ref=primarySource==='netease'?{source:'netease',id:primaryId}:await searchLyricRef(song,'netease');if(ref?.id){const fallback=await fetchLyricPayload(ref.source,ref.id);if(fallback?.translation&&lyricTimelinesMatch(original,fallback.translation))translation=fallback.translation;}}catch(error){console.warn('[音乐播放器] 网易云翻译补全失败',error);}if(!original)for(const source of ['netease','joox','bilibili']){if(source===primarySource)continue;try{const ref=await searchLyricRef(song,source);if(!ref?.id)continue;const fallback=await fetchLyricPayload(ref.source,ref.id);if(!fallback?.original||!lyricFitsAudio(fallback.original))continue;original=fallback.original;resultSource=ref.source;resultId=ref.id;raw=fallback.raw||raw;if(fallback.translation&&lyricTimelinesMatch(original,fallback.translation))translation=fallback.translation;break;}catch(error){console.warn(`[音乐播放器] ${source} 歌词回退失败`,error);}}const result={source:resultSource,id:resultId,original,translation,raw};if(original||translation)lyricCache.set(key,result);return result;}
  function paintTime(){const el=DOC.getElementById(ID);if(!el)return;const duration=audio.duration,now=audio.currentTime;el.querySelector('.progress').value=Number.isFinite(duration)&&duration>0?Math.round(now/duration*1000):0;el.querySelector('.time').textContent=`${clock(now)} / ${clock(duration)}`;const active=[...lyricTimeline].reverse().find(x=>x.time<=now),words=active?.lines?.filter(Boolean).join('\n')||'';currentLyricWords=words;el.querySelector('.lyrics').textContent=words||'暂无歌词';el.querySelector('.immersive-lyric').textContent=words||'暂无歌词';renderDesktopLyrics(words);}
  const mediaText = code => ({1:'MEDIA_ERR_ABORTED：音频加载被中止',2:'MEDIA_ERR_NETWORK：加载音频时发生网络错误',3:'MEDIA_ERR_DECODE：浏览器无法解码音频',4:'MEDIA_ERR_SRC_NOT_SUPPORTED：音频地址或格式不受支持'})[code] || '未知音频错误';
  const isNotAllowed = error => error?.name === 'NotAllowedError';
  const getResponseUrl = data => data?.url||data?.data?.url||data?.data?.[0]?.url||data?.pic||'';
  async function gdCover(s){try{const source=s.source||'netease',picId=String(s.coverId||'').trim();if(s.cover&&/^https?:\/\//i.test(s.cover))return s.cover;if(!picId){console.warn('[音乐播放器] 没有 pic_id，无法获取 GD 封面',s);return '';}if(source==='bilibili'){if(picId.startsWith('//'))return `https:${picId}`;if(/^https?:\/\//i.test(picId))return picId;}const u=new URL(GD_API);u.searchParams.set('types','pic');u.searchParams.set('source',source);u.searchParams.set('id',picId);u.searchParams.set('size','500');console.log('[GD封面请求]',source,picId);const response=await fetch(u);if(!response.ok)throw Error(`GD 封面请求失败：${response.status}`);const data=await response.json(),coverUrl=getResponseUrl(data);console.log('[GD封面响应]',data);console.log('[GD最终封面URL]',coverUrl);return coverUrl;}catch(error){console.warn('[音乐播放器] GD 封面获取失败',error);return '';}}
  function playUrl(url, label = '音源', isolated = false){return new Promise((resolve,reject)=>{const player=isolated?new ROOT.Audio():audio;let done=false;const finish=err=>{if(done)return;done=true;clearTimeout(timer);events.forEach(([n,f])=>player.removeEventListener(n,f));err?reject(err):resolve();};const log=name=>()=>console.info('[音乐播放器]',name,{url,src:player.src,currentSrc:player.currentSrc,errorCode:player.error?.code,errorMessage:player.error?.message,networkState:player.networkState,readyState:player.readyState});const bad=()=>{const err=new Error(mediaText(player.error?.code));err.media={code:player.error?.code,message:player.error?.message,currentSrc:player.currentSrc,networkState:player.networkState,readyState:player.readyState};console.error('[音乐播放器] Audio 错误',err.media);finish(err);};const good=()=>{console.info('[音乐播放器]',label,'开始播放',{url,currentSrc:player.currentSrc});finish();};const events=[['loadstart',log('loadstart')],['loadedmetadata',log('loadedmetadata')],['loadeddata',log('loadeddata')],['canplay',log('canplay')],['play',good],['playing',good],['stalled',log('stalled')],['suspend',log('suspend')],['abort',log('abort')],['error',bad]];events.forEach(([n,f])=>player.addEventListener(n,f));const timer=ROOT.setTimeout(()=>{const err=new Error('音源响应超时');err.media={currentSrc:player.currentSrc,networkState:player.networkState,readyState:player.readyState};finish(err);},15000);player.preload='auto';player.src=url;const playPromise=player.play();if(playPromise?.then)playPromise.then(good).catch(err=>{if(isNotAllowed(err))finish(err);else if(!player.error){const failure=new Error(err?.message||'浏览器无法开始播放');failure.media={currentSrc:player.currentSrc,networkState:player.networkState,readyState:player.readyState};finish(failure);}});});}
  async function gdFallback(s){/* 搜索默认首项来自网易云；收藏也以它为准，旧平台 ID 不再作为不安全兜底。 */for(const source of [...new Set(['netease',s.source,...GD_SOURCES].filter(Boolean))])try{const search=new URL(GD_API);search.searchParams.set('types','search');search.searchParams.set('source',source);search.searchParams.set('name',`${s.title} ${s.artist}`);search.searchParams.set('count','20');search.searchParams.set('pages','1');const response=await fetch(search);if(!response.ok)continue;const data=await response.json(),rows=Array.isArray(data)?data:(data?.data||[]),hit=bestSongHit(rows,s);if(!hit?.id)continue;const url=new URL(GD_API);url.searchParams.set('types','url');url.searchParams.set('source',source);url.searchParams.set('id',String(hit.id));url.searchParams.set('br','320');const linkResponse=await fetch(url);if(!linkResponse.ok)continue;const info=await linkResponse.json(),audioUrl=info?.url||info?.data?.url||info?.data?.[0]?.url||'';if(!audioUrl)continue;await playUrl(audioUrl);const lyricId=String(hit.lyric_id||hit.id||''),coverId=String(hit.pic_id||hit.album?.pic_id||hit.album?.picId||hit.al?.pic_str||hit.al?.pic||'');return {...s,id:`${source}:${hit.id}`,mediaId:String(hit.id),source,lyricId,gdSource:source,gdLyricId:lyricId,coverId,cover:'',audio:audioUrl};}catch(error){console.warn(`[音乐播放器] ${source} 严格匹配失败`,error);}return null;}
  async function gdMetadata(s){try{let x=s;if(!x.lyricId){const u=new URL(GD_API);u.searchParams.set('types','search');u.searchParams.set('source',s.source);u.searchParams.set('name',`${s.title} ${s.artist}`);u.searchParams.set('count','10');u.searchParams.set('pages','1');const r=await fetch(u);const rows=await r.json();const hit=(Array.isArray(rows)?rows:rows.data||[]).find(v=>(v.name||v.title||'').toLowerCase()===s.title.toLowerCase());if(hit)x={...s,lyricId:String(hit.lyric_id||hit.id||''),mediaId:String(hit.id||s.mediaId)};}return {...s,gdSource:x.source,gdLyricId:x.lyricId||x.mediaId};}catch{return s;}}
  async function metingCover(s){for(const base of METING_COVER_APIS)try{const u=new URL(base);u.searchParams.set('server','netease');u.searchParams.set('type','search');u.searchParams.set('id',`${s.title} ${s.artist}`);const r=await fetch(u);if(!r.ok)continue;const data=await r.json(),rows=Array.isArray(data)?data:(data?.data||[]),hit=bestSongHit(rows,s);if(typeof hit?.pic==='string'&&hit.pic)return hit.pic;}catch(error){console.warn(`[音乐播放器] Meting 封面失败：${base}`,error);}return '';}
  function imageLoads(url,timeout=8000){return new Promise(resolve=>{if(!/^https?:\/\//i.test(String(url||'')))return resolve(false);const image=new ROOT.Image();let done=false;const finish=ok=>{if(done)return;done=true;ROOT.clearTimeout(timer);image.onload=null;image.onerror=null;resolve(ok);};const timer=ROOT.setTimeout(()=>finish(false),timeout);image.onload=()=>finish(true);image.onerror=()=>finish(false);image.src=url;});}
  async function resolveCover(s,excluded=[]){const blocked=new Set(excluded.filter(Boolean).map(x=>String(x).replace(/#.*$/,''))),candidates=[],meting=await metingCover(s);if(meting)candidates.push(meting);try{const gd=await gdCover({...s,cover:''});if(gd)candidates.push(gd);}catch{}if(s.cover)candidates.push(s.cover);for(const url of [...new Set(candidates)]){if(blocked.has(String(url).replace(/#.*$/,'')))continue;if(await imageLoads(url))return url;}return '';}
  async function applyCurrentCover(s,request){const pic=await resolveCover(s);if(request!==playRequest||current!==s||!pic)return;s.cover=pic;const img=DOC.querySelector(`#${ID} .now img`);if(img){img.style.visibility='visible';img.onerror=async()=>{const failed=img.src;img.removeAttribute('src');const fallback=await resolveCover({...s,cover:''},[failed]);if(request===playRequest&&current===s&&fallback){s.cover=fallback;show(s);if(settings.favorites?.includes(s))save();}};show(s);}if(settings.favorites?.includes(s))save();}
