  async function loadLyrics(s,request){lyricTimeline=[];currentLyricWords='';const el=DOC.querySelector(`#${ID} .lyrics`);if(el)el.textContent='加载歌词…';try{let resolved={original:'',translation:''};for(let attempt=0;attempt<5;attempt++){if(request!==playRequest||current!==s)return;resolved=await resolveLyrics(s);if(resolved.original||resolved.translation)break;if(attempt<4)await waitForRetry(600*(attempt+1));}if(request!==playRequest||current!==s)return;lyricTimeline=mergeLyricTimeline(resolved.original,resolved.translation);const inlineBilingual=lyricTimeline.some(x=>x.lines.length>1);console.log('[音乐播放器] 歌词解析结果',{source:resolved.source,id:resolved.id,original:!!resolved.original,translation:!!resolved.translation,inlineBilingual,lineCount:lyricTimeline.length,raw:resolved.raw});if(!lyricTimeline.length)setStatus('当前歌曲没有可用歌词');}catch(error){if(request!==playRequest||current!==s)return;console.warn('[音乐播放器] 歌词加载失败',error);setStatus(`歌词加载失败：${error.message}`);}paintTime();}
