  async function recommendation(force=false){const chat=context()?.chat||[];let m;for(let i=chat.length-1;i>=0;i--)if(!chat[i]?.is_user){m={i,text:chat[i].mes};break;}const r=m&&parse(m.text);if(!r){if(force)toast('warning','本层没有 music_recommend 标签');return;}const key=`${m.i}:${r.title}:${r.artist}`;if(!force&&key===lastRecommendation)return;lastRecommendation=key;DOC.querySelector(`#${ID} .reason`).textContent=r.reason?`推荐：${r.reason}`:'';if(settings.autoLoad||force)await search(`${r.title} ${r.artist}`,true,true,'本层推荐候选');}
  async function importPlaylist(link){
    try{
      const u=new URL(String(link||'').trim()),host=u.hostname.toLowerCase();
      const source=/music\.163\.com$/.test(host)?'netease':/(^|\.)qq\.com$/.test(host)?'tencent':/(^|\.)kugou\.com$/.test(host)?'kugou':'';
      const pathId=u.pathname.match(/(?:playlist|detail|songlist|plist\/list)\/(?:gcid_)?([\w-]+)/i)?.[1];
      const rawId=u.searchParams.get('id')||u.searchParams.get('disstid')||u.searchParams.get('playlist')||u.searchParams.get('specialid')||u.searchParams.get('global_collection_id')||pathId||'';
      const id=String(rawId).replace(/^(?:collection_|gcid_)/i,'');
      if(!source||!id)throw Error('仅支持网易云、QQ 音乐或酷狗歌单链接');
      setStatus('正在导入歌单…');
      const ids=source==='kugou'?[...new Set([rawId,id,`gcid_${id}`].filter(Boolean))]:[id];
      let rows=null,lastError=null;
      outer:for(const playlistId of ids)for(const base of METING_COVER_APIS)try{
        const api=new URL(base);api.searchParams.set('server',source);api.searchParams.set('type','playlist');api.searchParams.set('id',playlistId);
        const r=await fetch(api);if(!r.ok)throw Error(`接口返回 ${r.status}`);
        const data=await r.json();if(!Array.isArray(data)||!data.length)throw Error('接口没有返回歌曲');
        rows=data;break outer;
      }catch(error){lastError=error;console.warn(`[音乐播放器] 歌单接口失败，尝试备用接口：${base}`,error);}
      if(!rows)throw Error(`歌单读取失败：${lastError?.message||'所有接口均不可用'}`);
      settings.favorites=settings.favorites||[];const known=new Set(settings.favorites.map(x=>x.id));let added=0;
      for(const x of rows.slice(0,200)){let mediaId='';try{mediaId=new URL(x.url||'').searchParams.get('id')||'';}catch{}const song={id:`${source}:${mediaId||x.title}:${x.author||''}`,mediaId,title:x.title||'',artist:x.author||'',cover:x.pic||'',audio:'',source};if(song.title&&!known.has(song.id)){settings.favorites.push(strip(song));known.add(song.id);added++;}}
      save();setStatus(added?`已导入 ${added} 首到收藏`:'歌单歌曲均已存在，无需重复导入');toast(added?'success':'info',added?`已导入 ${added} 首到收藏`:'歌单歌曲均已存在');
    }catch(error){setStatus(error.message);toast('error',error.message);}
  }
