  function optimizeWindowInteractions(el){
    if(!el||el.dataset.pointerOptimized)return;
    el.dataset.pointerOptimized='1';
    const requestFrame=ROOT.requestAnimationFrame?.bind(ROOT)||((callback)=>ROOT.setTimeout(callback,16));
    const cancelFrame=ROOT.cancelAnimationFrame?.bind(ROOT)||ROOT.clearTimeout.bind(ROOT);
    const wrap=target=>{
      if(!target?.onpointermove)return;
      const down=target.onpointerdown,move=target.onpointermove,up=target.onpointerup,cancel=target.onpointercancel,lost=target.onlostpointercapture;
      let active=false,frame=0,pending=null;
      const flush=()=>{frame=0;const event=pending;pending=null;if(event)move?.call(target,event);};
      target.onpointerdown=e=>{down?.call(target,e);if(e.defaultPrevented){active=true;el.classList.add('pointer-interacting');}};
      target.onpointermove=e=>{if(!active){move?.call(target,e);return;}pending=e;if(e.cancelable)e.preventDefault();if(!frame)frame=requestFrame(flush);};
      const finish=(handler,e,flushMove)=>{if(frame){cancelFrame(frame);frame=0;}if(flushMove)flush();else pending=null;handler?.call(target,e);active=false;el.classList.remove('pointer-interacting');};
      target.onpointerup=e=>finish(up,e,true);
      target.onpointercancel=e=>finish(cancel,e,false);
      target.onlostpointercapture=e=>finish(lost||cancel,e,false);
    };
    wrap(el.querySelector('.head'));
    el.querySelectorAll('.resize-handle,.mini-cover-shell').forEach(wrap);
  }
